"""
Regression test for dark mode text threshold setting on Qt 6.4.

This test verifies that the colors.webpage.darkmode.threshold.text setting
is correctly translated to 'ForegroundBrightnessThreshold' on Qt 6.4,
whereas it should be 'TextBrightnessThreshold' on earlier Qt versions.

Issue: On Qt 6.4, the threshold.text setting has no effect due to
incorrect Chromium key name mapping.
"""

import sys
import copy
import dataclasses
import enum
from typing import Any, Iterator, Mapping, MutableMapping, Optional, Set, Tuple, Union


# Minimal implementation of darkmode.py settings classes for testing
@dataclasses.dataclass
class _Setting:
    """A single dark mode setting."""

    option: str
    chromium_key: str
    mapping: Optional[Mapping[Any, Union[str, int]]] = None

    def _value_str(self, value: Any) -> str:
        if self.mapping is None:
            return str(value)
        return str(self.mapping[value])

    def chromium_tuple(self, value: Any) -> Tuple[str, str]:
        return self.chromium_key, self._value_str(value)

    def with_prefix(self, prefix: str) -> '_Setting':
        return _Setting(
            option=self.option,
            chromium_key=prefix + self.chromium_key,
            mapping=self.mapping,
        )


class _Definition:
    """A collection of dark mode setting names for the given QtWebEngine version."""

    def __init__(
            self,
            *args: _Setting,
            mandatory: Set[str],
            prefix: str,
            switch_names: Mapping[Optional[str], str] = None,
    ) -> None:
        self._settings = args
        self.mandatory = mandatory
        self.prefix = prefix

        if switch_names is not None:
            self._switch_names = switch_names
        else:
            self._switch_names = {None: 'blink-settings'}

    def prefixed_settings(self) -> Iterator[Tuple[str, _Setting]]:
        """Get all "prepared" settings."""
        for setting in self._settings:
            switch = self._switch_names.get(setting.option, self._switch_names[None])
            yield switch, setting.with_prefix(self.prefix)

    def copy_with(self, attr: str, value: Any) -> '_Definition':
        """Get a new _Definition object with a changed attribute."""
        new = copy.copy(self)
        setattr(new, attr, value)
        return new

    def copy_add_setting(self, setting: _Setting) -> '_Definition':
        """Get a new _Definition object with an additional setting."""
        new = copy.copy(self)
        new._settings = self._settings + (setting,)
        return new

    def copy_replace_setting(self, option: str, chromium_key: str) -> '_Definition':
        """Get a new _Definition object with `option` replaced by `new` chromium_key."""
        new = copy.deepcopy(self)

        for setting in new._settings:
            if setting.option == option:
                setting.chromium_key = chromium_key
                return new

        raise ValueError(f"Setting {option} not found in {self}")


class Variant(enum.Enum):
    """A dark mode variant."""
    qt_515_3 = enum.auto()
    qt_63 = enum.auto()
    qt_64 = enum.auto()


_BOOLS = {
    True: 'true',
    False: 'false',
}

_INT_BOOLS = {
    True: '1',
    False: '0',
}

_ALGORITHMS_NEW = {
    'brightness-rgb': 1,
}

_IMAGE_POLICIES = {
    'always': 0,
    'smart': 2,
}

# Build the definitions exactly as in darkmode.py
_DEFINITIONS: MutableMapping[Variant, _Definition] = {
    Variant.qt_515_3: _Definition(
        _Setting('enabled', 'forceDarkModeEnabled', _BOOLS),
        _Setting('algorithm', 'InversionAlgorithm', _ALGORITHMS_NEW),
        _Setting('policy.images', 'ImagePolicy', _IMAGE_POLICIES),
        _Setting('grayscale.all', 'IsGrayScale', _BOOLS),
        _Setting('threshold.text', 'TextBrightnessThreshold'),
        _Setting('threshold.background', 'BackgroundBrightnessThreshold'),

        mandatory={'enabled', 'policy.images'},
        prefix='',
        switch_names={'enabled': 'blink-settings', None: 'dark-mode-settings'},
    ),
}

_DEFINITIONS[Variant.qt_63] = _DEFINITIONS[Variant.qt_515_3].copy_add_setting(
    _Setting('increase_text_contrast', 'IncreaseTextContrast', _INT_BOOLS),
)

_DEFINITIONS[Variant.qt_64] = _DEFINITIONS[Variant.qt_63].copy_replace_setting(
    'threshold.text', 'ForegroundBrightnessThreshold',
)


def get_threshold_text_chromium_key(variant: Variant) -> Optional[str]:
    """
    Get the Chromium key name for the threshold.text setting in the given variant.

    Returns the Chromium key, or None if the setting is not found.
    """
    definition = _DEFINITIONS[variant]
    for switch_name, setting in definition.prefixed_settings():
        if setting.option == 'threshold.text':
            return setting.chromium_key
    return None


def test_qt_63_threshold_text_key():
    """Test that Qt 6.3 uses TextBrightnessThreshold for threshold.text."""
    key = get_threshold_text_chromium_key(Variant.qt_63)
    assert key == 'TextBrightnessThreshold', (
        f"Qt 6.3 threshold.text should map to 'TextBrightnessThreshold', "
        f"got '{key}'"
    )
    print("✓ Qt 6.3 correctly uses 'TextBrightnessThreshold'")


def test_qt_64_threshold_text_key():
    """Test that Qt 6.4 uses ForegroundBrightnessThreshold for threshold.text."""
    key = get_threshold_text_chromium_key(Variant.qt_64)
    assert key == 'ForegroundBrightnessThreshold', (
        f"Qt 6.4 threshold.text should map to 'ForegroundBrightnessThreshold', "
        f"got '{key}'"
    )
    print("✓ Qt 6.4 correctly uses 'ForegroundBrightnessThreshold'")


def test_qt_515_3_threshold_text_key():
    """Test that Qt 5.15.3 uses TextBrightnessThreshold for threshold.text."""
    key = get_threshold_text_chromium_key(Variant.qt_515_3)
    assert key == 'TextBrightnessThreshold', (
        f"Qt 5.15.3 threshold.text should map to 'TextBrightnessThreshold', "
        f"got '{key}'"
    )
    print("✓ Qt 5.15.3 correctly uses 'TextBrightnessThreshold'")


def test_qt_64_has_different_key_than_qt_63():
    """Test that Qt 6.4 and Qt 6.3 have different keys for threshold.text."""
    key_63 = get_threshold_text_chromium_key(Variant.qt_63)
    key_64 = get_threshold_text_chromium_key(Variant.qt_64)

    assert key_63 != key_64, (
        f"Qt 6.4 and Qt 6.3 should have different chromium keys "
        f"for threshold.text. Got: Qt 6.3={key_63}, Qt 6.4={key_64}"
    )
    print(f"✓ Qt 6.3 and Qt 6.4 have different keys: {key_63} vs {key_64}")


def test_threshold_text_setting_exists():
    """Test that threshold.text setting exists in all variants."""
    for variant in [Variant.qt_515_3, Variant.qt_63, Variant.qt_64]:
        definition = _DEFINITIONS[variant]
        found = False
        for setting in definition._settings:
            if setting.option == 'threshold.text':
                found = True
                break
        assert found, f"threshold.text setting not found in {variant.name}"
    print("✓ threshold.text setting exists in all variants")


def test_copy_replace_setting_actually_replaces():
    """Test that copy_replace_setting actually modifies the chromium_key."""
    # Verify that the original qt_63 has TextBrightnessThreshold
    qt_63_def = _DEFINITIONS[Variant.qt_63]
    for setting in qt_63_def._settings:
        if setting.option == 'threshold.text':
            assert setting.chromium_key == 'TextBrightnessThreshold', (
                f"Qt 6.3 definition should have TextBrightnessThreshold, "
                f"got {setting.chromium_key}"
            )
            break

    # Verify that qt_64 has ForegroundBrightnessThreshold
    qt_64_def = _DEFINITIONS[Variant.qt_64]
    for setting in qt_64_def._settings:
        if setting.option == 'threshold.text':
            assert setting.chromium_key == 'ForegroundBrightnessThreshold', (
                f"Qt 6.4 definition should have ForegroundBrightnessThreshold, "
                f"got {setting.chromium_key}"
            )
            break

    print("✓ copy_replace_setting correctly modified the chromium_key")


def test_threshold_text_chromium_tuple():
    """Test that chromium_tuple returns the correct key-value pair."""
    qt_64_def = _DEFINITIONS[Variant.qt_64]

    for setting in qt_64_def._settings:
        if setting.option == 'threshold.text':
            key, value = setting.chromium_tuple(100)
            assert key == 'ForegroundBrightnessThreshold', (
                f"Expected key 'ForegroundBrightnessThreshold', got '{key}'"
            )
            assert value == '100', (
                f"Expected value '100', got '{value}'"
            )
            break

    print("✓ chromium_tuple returns correct ForegroundBrightnessThreshold key")


if __name__ == '__main__':
    try:
        test_qt_515_3_threshold_text_key()
        test_qt_63_threshold_text_key()
        test_qt_64_threshold_text_key()
        test_qt_64_has_different_key_than_qt_63()
        test_threshold_text_setting_exists()
        test_copy_replace_setting_actually_replaces()
        test_threshold_text_chromium_tuple()

        print("\n" + "="*60)
        print("All regression tests passed!")
        print("="*60)
        sys.exit(0)
    except AssertionError as e:
        print(f"\n✗ TEST FAILED: {e}")
        sys.exit(1)
    except Exception as e:
        print(f"\n✗ ERROR: {e}")
        import traceback
        traceback.print_exc()
        sys.exit(1)

